const body = $json.body || $json;
const contentIdeaId = Number(body.contentIdeaId || 0);
const workflowRunId = Number(body.workflowRunId || 0);
const idempotencyKey = String(body.idempotencyKey || '').trim() || null;
const topic = String(body.topic || '').trim();
const script = String(body.script || '').trim();
const caption = String(body.caption || '').trim();
const keyword = String(body.keyword || topic || '').trim();
const category = String(body.category || '').trim() || null;
const tiktokAccountOpenId = String(body.tiktokAccountOpenId || '').trim() || null;
const source = String(body.source || 'n8n-render-remotion').trim();

const ALLOWED_QUALITIES = ['draft', 'standard', 'high', 'premium'];
const rawQualityProfile = String(body.qualityProfile || '').trim();
const templateId = 'tiktok-scene-sequence';
const qualityProfile = ALLOWED_QUALITIES.includes(rawQualityProfile) ? rawQualityProfile : 'high';
const sceneCountInput = Number(body.sceneCount || 1);
const sceneCount = Number.isInteger(sceneCountInput) ? Math.min(10, Math.max(1, sceneCountInput)) : 1;
const minDurationSec = Math.max(15, sceneCount * 3);
const requestedDurationSec = Number(body.durationSec || minDurationSec);
const durationSec = Math.min(60, Math.max(minDurationSec, Number.isFinite(requestedDurationSec) ? requestedDurationSec : minDurationSec));

if (!contentIdeaId || contentIdeaId <= 0) throw new Error('contentIdeaId invalide');
if (!workflowRunId || workflowRunId <= 0) throw new Error('workflowRunId invalide');
if (!topic) throw new Error('topic manquant');
if (!script) throw new Error('script manquant');
if (!caption) throw new Error('caption manquante');
if (!keyword) throw new Error('keyword manquant');

const hook = String(body.hook || script.split(/[.!?\n]/)[0] || topic).trim().slice(0, 120);
const cta = String(body.cta || '').trim() || null;

return [{ json: { contentIdeaId, workflowRunId, idempotencyKey, topic, script, caption, keyword, category, tiktokAccountOpenId, source, hook, cta, templateId, qualityProfile, durationSec, sceneCount } }];

// Wrap : combine l'input validé avec le renderJob retourné par scenes/build
// pour préserver le contrat des nodes downstream qui réfèrent à
// $('Build Render Job').item.json.{contentIdeaId,workflowRunId,renderJob,...}.
const input = $('Validate Input').item.json;
const renderJob = $json;
if (!renderJob || !renderJob.contractVersion) {
  throw new Error('scenes/build n\'a pas retourné un renderJob valide');
}
return [{ json: { ...input, renderJob } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const input = $('Build Render Job').item.json;
const render = $('HTTP: RenderVideo Render').item.json;
const idempotencyKey = String(input.idempotencyKey || '').trim();

const body = JSON.stringify({
  status: 'SUCCEEDED',
  message: 'Remotion render completed.',
  responsePayload: JSON.stringify({ contentIdeaId: input.contentIdeaId, renderId: render.renderId, outputUrl: render.outputUrl, engine: 'remotion' })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + input.workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;
const response = await new Promise((resolve, reject) => {
  const req = client.request({
    protocol: url.protocol,
    hostname: url.hostname,
    port: url.port || (url.protocol === 'https:' ? 443 : 80),
    path: url.pathname + url.search,
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body),
      'X-Video-Ops-Callback-Secret': callbackSecret,
      ...(idempotencyKey ? { 'X-Idempotency-Key': idempotencyKey } : {}),
      'X-Request-Timestamp': Date.now().toString()
    }
  }, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
  });
  req.on('error', reject);
  req.setTimeout(20000, () => req.destroy(new Error('Callback timeout')));
  req.write(body);
  req.end();
});

if (response.statusCode < 200 || response.statusCode >= 300) {
  throw new Error('Callback failed: ' + response.statusCode + ' ' + response.body);
}

return [{ json: { ok: true, callbackStatusCode: response.statusCode } }];
